import { Link } from "react-router-dom";
import "../styles/mainmenu/MainMenu.css";

const cargarPartidaDesdeArchivo = (event) => {
    const file = event.target.files[0];
    if (!file) return;
  
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const partida = JSON.parse(e.target.result);
        const { equipo, calendario, numLigas } = partida;
  
        localStorage.setItem('equipo', JSON.stringify(equipo));
        localStorage.setItem('calendario', JSON.stringify(calendario));
        localStorage.setItem('numLigas', JSON.stringify(numLigas));
  
        alert('Partida cargada con éxito.');
        window.location.reload(); // si necesitas recargar el estado
      } catch (err) {
        alert('Archivo inválido.');
      }
    };
    reader.readAsText(file);
  };

function CargarPartida() {
    return (
        localStorage.clear(),
        <div className="main-menu">
            <div className="menu-options>">
                <Link to="start-page" className="menu-link">
                    <button className="menu-button">
                        Play
                    </button>
                </Link>
            </div>
        </div>
    );
}

export default MainMenu; // Asegúrate de exportar por defecto
